```csharp
using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Text.RegularExpressions;

namespace OzonParser
{
    class Program
    {
        static void Main(string[] args)
        {
            string url = "https://www.ozon.ru/category/obuv-dlja-muzhchin-16553/";

            // Создаем HttpClient (установите пакет System.Net.Http, если еще не установлен)
            HttpClient httpClient = new HttpClient();

            // Загружаем HTML контент страницы
            string html = httpClient.GetStringAsync(url).Result;

            // Паттерн для поиска блоков с товарами
            string pattern = "<div class=\"b5v1[^>]+?>(.*?)</div>";

            // Находим все блоки с товарами в HTML
            MatchCollection productMatches = Regex.Matches(html, pattern, RegexOptions.Singleline);

            // Перебираем каждый блок с товаром
            foreach (Match productMatch in productMatches)
            {
                // Получаем HTML код товара
                string productHtml = productMatch.Groups[1].Value;

                // Паттерн для поиска названия товара
                string namePattern = "<a class=\"c6e8\"[^>]*?>(.*?)</a>";
                Match nameMatch = Regex.Match(productHtml, namePattern);
                string name = nameMatch.Groups[1].Value.Trim();

                // Паттерн для поиска цены товара
                string pricePattern = "<div class=\"c6q2 t7u9 s1m6\"[^>]*?>(.*?)</div>";
                Match priceMatch = Regex.Match(productHtml, pricePattern);
                string price = priceMatch.Groups[1].Value.Trim();

                // Выводим результаты
                Console.WriteLine("Название: " + name);
                Console.WriteLine("Цена: " + price);
                Console.WriteLine("---------------------------------");
            }

            Console.ReadLine();
        }
    }
}
```

